#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor conv2d_min_tanh_tanh_impl_npu(const at::Tensor& x,
                                         const at::Tensor& weight,
                                         c10::optional<at::Tensor> bias) {
    // Output shape: [N, 1, H-kH+1, W-kW+1]
    TORCH_CHECK(x.dim() == 4, \"x must be 4D NCHW\");
    TORCH_CHECK(weight.dim() == 4, \"weight must be 4D OIHW\");
    const auto N = x.size(0);
    const auto H = x.size(2);
    const auto W = x.size(3);
    const auto kH = weight.size(2);
    const auto kW = weight.size(3);
    TORCH_CHECK(H >= kH && W >= kW, \"Invalid kernel size vs input\");
    const auto Hout = H - kH + 1;
    const auto Wout = W - kW + 1;
    at::Tensor result = at::empty({N, 1, Hout, Wout}, x.options());

    if (bias.has_value()) {
        EXEC_NPU_CMD(aclnnConv2dMinTanhTanhCustom, x, weight, bias.value(), result);
    } else {
        // Pass an undefined tensor for optional input
        at::Tensor none_bias;
        EXEC_NPU_CMD(aclnnConv2dMinTanhTanhCustom, x, weight, none_bias, result);
    }
    return result;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl(\"conv2d_min_tanh_tanh_custom\", &conv2d_min_tanh_tanh_impl_npu);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def(\"conv2d_min_tanh_tanh_custom\", &conv2d_min_tanh_tanh_impl_npu,
          \"Fused Conv2D + channel-min + tanh + tanh (Conv2dMinTanhTanhCustom on NPU)\",
          py::arg(\"x\"), py::arg(\"weight\"), py::arg(\"bias\") = py::none());
}
